            info: "Link points to the latest successful build for this branch."
        }), { 
            headers: { ...corsHeaders, 'Content-Type': 'application/json' } 
        });
    }

    return new Response(JSON.stringify({ success: false, error: "Action not implemented" }), { 
        status: 400, 
        headers: corsHeaders 
    });

  } catch (error) {
